from flask import Flask, request, jsonify
from collections import defaultdict
import numpy as np
import json

app = Flask(__name__)
labels = defaultdict(list)

@app.route('/annotate', methods=['POST'])
def annotate():
    data = request.json
    image_id = data.get('image_id')
    label = data.get('label')
    annotator_id = data.get('annotator_id')

    if image_id and label and annotator_id:
        labels[image_id].append({'label': label, 'annotator_id': annotator_id})
        return jsonify(success=True), 201
    return jsonify(success=False, message="Invalid input"), 400

@app.route('/aggregate', methods=['GET'])
def aggregate():
    aggregated_labels = {}
    for image_id, annotations in labels.items():
        label_counts = defaultdict(int)
        for annotation in annotations:
            label_counts[annotation['label']] += 1
        majority_label = max(label_counts, key=label_counts.get)
        aggregated_labels[image_id] = majority_label
    return jsonify(aggregated_labels)

@app.route('/train', methods=['POST'])
def train_model():
    # Dummy training function
    data = request.json
    aggregated_data = aggregate().get_json()
    # Here you would add your model training process
    # For the purpose of this example we will just return success.
    return jsonify(success=True, message="Model trained with aggregated data.")

if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0', port=5000)